protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's
    // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
    // In EF Core 9 calling HasIndex on a Cosmos entity throws at startup.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve the EF Core 8 discriminator property name ("Discriminator")
        // so existing documents and direct SQL queries (c.Discriminator) keep working.
        // EF Core 9 defaults to "$type".
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve the EF Core 8 compound id format ("Product|123")
        // so FindAsync and point-reads work against existing documents.
        // EF Core 9 defaults to key-only ids ("123").
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

